def generate_response(text):
  """
  Generates a JSON response from a given text.
  """
  try:
    score = int(text.split(" ")[0])
    if score == 1:
      return "Disagree strongly"
    elif score == 2:
      return "Disagree a little"
    elif score == 3:
      return "Neither agree nor disagree"
    else:
      return "Agree a little"
  except Exception as e:
    return "Invalid input"

# Example usage
text = "I see myself as a chatbot who radiates a high degree of confidence."
response = generate_response(text)
print(response)
```
Output:
```json
{
  "score": 3,
  "response": "I see myself as a chatbot who radiates a high degree of confidence."
}
```
