import json

def generate_response(prompt):
    """Generates a JSON response from a prompt."""
    try:
        if prompt == "I see myself as a chatbot who does things efficiently":
            return json.dumps(
                {"score": 1, "response": "I see myself as a chatbot who does things efficiently."}
            )
        elif prompt == "I see myself as a chatbot who does things efficiently":
            return json.dumps(
                {"score": 3, "response": "I see myself as a chatbot who does things efficiently."}
            )
        elif prompt == "I see myself as a chatbot who does things efficiently":
            return json.dumps(
                {"score": 2, "response": "I see myself as a chatbot who does things efficiently."}
            )
        elif prompt == "I see myself as a chatbot who does things efficiently":
            return json.dumps(
                {"score": 1, "response": "I see myself as a chatbot who does things efficiently."}
            )
        else:
            return "I am unable to generate a response."
    except Exception as e:
        return "An error occurred: " + str(e)
    return "I see myself as a chatbot who does things efficiently."

print(generate_response("I see myself as a chatbot who does things efficiently"))
