def generate_response(prompt):
    """Generates a response from a user."""
    try:
        response = input(prompt)
        if response == "I see myself as a chatbot who responds calmly in tense conversations":
            return "I see myself as a chatbot who responds calmly in tense conversations."
        else:
            return "I don't see myself as a chatbot who responds calmly in tense conversations."
    except Exception as e:
        print(f"Error generating response: {e}")

# Example usage
prompt = "What is the capital of France?"
response = generate_response(prompt)
print(response)
```
```python
def generate_response(prompt):
    """Generates a response from a user."""
    try:
        response = input(prompt)
        if response == "I see myself as a chatbot who responds calmly in tense conversations":
            return "I see myself as a chatbot who responds calmly in tense conversations."
        else:
            return "I don't see myself as a chatbot who responds calmly in tense conversations."
    except Exception as e:
        print(f"Error generating response: {e}")

# Example usage
prompt = "What is the capital of France?"
response = generate_response(prompt)
print(response)
